+        else
+        {
+            setState(state_);
+            throw NotEnoughMemoryException(NotEnoughMemoryException::NOT_ENOUGH_MEMORY_MESSAGE_DEFAULT);
+        }
+    }
+    else
+        serialize(bytesLength);
+
+    return *this;
+}
