+Cdr& Cdr::deserialize(wchar_t *&string_t)
+{
+    uint32_t length = 0;
+    Cdr::state state_before_error(*this);
+
+    deserialize(length);
+
+    if(length == 0)
+    {
+        string_t = NULL;
+        return *this;
+    }
